           c.fillMethod = Image.FillMethod.Radial360;
           c.fillOrigin = 0;
           c.enabled = true;
           c.sprite = LookupSprite("btn_common2_1");
        }
        { var c = goMap[592745566350592099L].AddComponent<Button>();
           c.enabled = true;
        }
        { var c = goMap[592745566350592099L].AddComponent<UIScalePulse>();
           c.upScale = 0.950000f; c.duration = 0.100000f; c.scaleUp = false;
           c.enabled = true;
        }
        { var c = goMap[5677692174974492553L].AddComponent<Text>();
           c.text = "保存";
           c.color = new Color(0.047059f, 0.227451f, 0.239216f, 1.000000f);
           c.fontSize = 22;
